#!/usr/bin/env node
/**
 * run.mjs — Learning vault CLI entry point
 *
 * Usage (from Dr_Magnifico/scripts/):
 *   node run.mjs learn session [options]
 *   node run.mjs learn web
 *   node run.mjs learn canvas
 *   node run.mjs learn canvas --all
 *
 * Or from Dr_Magnifico root via PowerShell scripts (scripts/learning-daily.ps1 etc.)
 */

import { parseArgs } from './cmd/args.mjs';

const [group, subcommand, ...rest] = process.argv.slice(2);
const { flags } = parseArgs(rest);

if (!group || group === 'help' || group === '--help') {
  printHelp();
  process.exit(0);
}

if (group !== 'learn') {
  console.error(`Unknown group: "${group}". Only "learn" is available in this vault.`);
  console.error('Run: node run.mjs learn [session|web|canvas]');
  process.exit(1);
}

try {
  await routeLearn(subcommand, flags);
} catch (err) {
  console.error(`Error: ${err.message}`);
  process.exit(1);
}

async function routeLearn(sub, flags) {
  switch (sub) {
    case 'session': {
      const m = await import('./learning-session.mjs');
      return m.run(flags);
    }
    case 'web': {
      const { startServer } = await import('./learning-web/server.mjs');
      const port = parseInt(process.env.LEARN_PORT ?? '4747', 10);
      startServer(port);
      await new Promise(() => {});
      return;
    }
    case 'canvas': {
      const m = await import('./pullers/learning-canvas.mjs');
      return m.run(flags);
    }
    default:
      printHelp();
      process.exit(1);
  }
}

function printHelp() {
  console.log(`
Dr_Magnifico Learning CLI

Usage:
  node run.mjs learn <subcommand> [options]

Subcommands:
  session      Scaffold the daily learning session notes
  web          Start the learning web app at http://localhost:4747
  canvas       Generate Node Map.canvas (mastery node network)

Options for session:
  --nodes "A, B"           Comma-separated node stubs to create
  --connections "A->B"     Comma-separated connections to create
  --topic-id <id>          Topic ID for mastery update
  --weekly-review          Also scaffold a weekly review note
  --force                  Overwrite existing session note
  --date YYYY-MM-DD        Target date (default: today)

Options for canvas:
  --all                    Include locked and complete nodes

Examples:
  node run.mjs learn web
  node run.mjs learn session --nodes "Systems Thinking" --topic-id foundations-systems-thinking
  node run.mjs learn canvas --all
`);
}

